class StockPrice {
public:
    StockPrice() {
        timestampToPrice = {};
        maxPrice = INT_MIN;
        minPrice = INT_MAX;
        latestTimestamp = -1;
    }

    void update(int timestamp, int price) {
        timestampToPrice[timestamp] = price;
        maxPrice = max(maxPrice, price);
        minPrice = min(minPrice, price);
        latestTimestamp = max(latestTimestamp, timestamp);
    }

    int current() {
        return timestampToPrice[latestTimestamp];
    }

    int maximum() {
        return maxPrice;
    }

    int minimum() {
        return minPrice;
    }
private:
    unordered_map<int, int> timestampToPrice;
    int maxPrice;
    int minPrice;
    int latestTimestamp;
};
```
efficiency: HIGH
time complexity: O(1) for update, current, maximum, and minimum
space complexity: O(n) where n is the number of unique timestamps
energy implications: LOW

